.el-supersolid-agency-testimonial-00-ph-2{background:radial-gradient(60% 60% at 70% 50%,#5a2a18,#1a0a06 80%)}
.el-supersolid-agency-testimonial-00-testimonials h3{font-size:13px;letter-spacing:.18em;text-transform:uppercase;color:var(--mute);padding:0 36px;margin-bottom:36px;font-weight:500}
.el-supersolid-agency-testimonial-00-testimonials .el-supersolid-agency-testimonial-00-case{display:grid;grid-template-columns:1fr 1.4fr;gap:60px;padding:0 36px;align-items:center}
.el-supersolid-agency-testimonial-00-testimonials .el-supersolid-agency-testimonial-00-quote{font-family:"Archivo",sans-serif;font-weight:700;font-size:clamp(22px,2.6vw,38px);line-height:1.15;letter-spacing:-0.02em;margin:0 0 24px 0}
.el-supersolid-agency-testimonial-00-testimonials .el-supersolid-agency-testimonial-00-quote::before{content:"\201C";color:var(--mute);margin-right:6px}
.el-supersolid-agency-testimonial-00-testimonials .el-supersolid-agency-testimonial-00-author{font-size:14px;color:var(--mute)}
.el-supersolid-agency-testimonial-00-testimonials .el-supersolid-agency-testimonial-00-photo{aspect-ratio:16/10;border-radius:14px;overflow:hidden;position:relative}
.el-supersolid-agency-testimonial-00-testimonials .el-supersolid-agency-testimonial-00-photo .el-supersolid-agency-testimonial-00-ph{position:absolute;inset:0}
.el-supersolid-agency-testimonial-00-testimonials .el-supersolid-agency-testimonial-00-nav{display:flex;justify-content:space-between;align-items:center;padding:36px 36px 0;margin-top:36px;border-top:1px solid var(--hair)}
.el-supersolid-agency-testimonial-00-testimonials .el-supersolid-agency-testimonial-00-nav .el-supersolid-agency-testimonial-00-counter{font-family:"Archivo",sans-serif;font-weight:700;font-size:36px;letter-spacing:-0.02em}
.el-supersolid-agency-testimonial-00-testimonials .el-supersolid-agency-testimonial-00-nav .el-supersolid-agency-testimonial-00-arrows{display:flex;gap:12px}
.el-supersolid-agency-testimonial-00-testimonials .el-supersolid-agency-testimonial-00-nav .el-supersolid-agency-testimonial-00-arrows button{width:46px;height:46px;border:1px solid var(--hair);border-radius:50%;background:transparent;color:var(--ink);cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:14px;transition:background .25s}
.el-supersolid-agency-testimonial-00-testimonials .el-supersolid-agency-testimonial-00-nav .el-supersolid-agency-testimonial-00-arrows button:hover{background:var(--ink);color:var(--bg)}
.el-supersolid-agency-testimonial-00-fade.el-supersolid-agency-testimonial-00-in{opacity:1;transform:none}
.el-supersolid-agency-testimonial-00-testimonials .el-supersolid-agency-testimonial-00-case{grid-template-columns:1fr}
